fun solve(s: String): Boolean {
  val st = ArrayDeque<Char>()
  val pairs = mapOf(')' to '(', ']' to '[', '}' to '{')
  for (ch in s) {
    if (ch == '(' || ch == '[' || ch == '{') st.addLast(ch)
    else if (ch == ')' || ch == ']' || ch == '}') {
      val top = if (st.isEmpty()) null else st.removeLast()
      if (top != pairs[ch]) return false
    }
  }
  return st.isEmpty()
}

