// C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
// Kotlin (JVM) · OpenCSV
// implementation("com.opencsv:opencsv:5.9")
import com.opencsv.CSVReader
import com.opencsv.CSVWriter
import java.io.*

fun solve(inputPath: String = "input.csv", outputPath: String = "output.csv") {
  CSVReader(InputStreamReader(FileInputStream(inputPath), Charsets.UTF_8)).use { r ->
    CSVWriter(OutputStreamWriter(FileOutputStream(outputPath), Charsets.UTF_8)).use { w ->
      val header = r.readNext() ?: return
      w.writeNext(header)
      var row = r.readNext()
      while (row != null) {
        val fixed = row.mapIndexed { i, v ->
          if (header.getOrNull(i)?.equals("Email", ignoreCase = true) == true) v?.trim()?.lowercase() ?: v
          else v
        }.toTypedArray()
        w.writeNext(fixed)
        row = r.readNext()
      }
    }
  }
}

