// Kotlin · jBCrypt (JVM)
import org.mindrot.jbcrypt.BCrypt

fun solve(password: String): Pair<String, Boolean> {
  val hash = BCrypt.hashpw(password, BCrypt.gensalt(12))
  val ok = BCrypt.checkpw(password, hash)
  return hash to ok
}

