// C0656 · Regex: extraer emails (Básico, Texto)
fun solve(text: String): List<String> {
  val re = Regex("[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}", RegexOption.IGNORE_CASE)
  val out = linkedSetOf<String>()
  re.findAll(text).forEach { out.add(it.value) }
  return out.toList()
}

